24	const API_BASE = import.meta.env.VITE_API_BASE ?? "";
25	
26	export class BayesApiError extends Error {
27	  constructor(
28	    public status: number,
29	    public code: string,
30	    public details: Record<string, unknown> = {},
31	  ) {
32	    super(`${code}: ${status}`);
33	    this.name = "BayesApiError";
34	  }
35	}
36	
37	export interface NormalizedMarketListFilters {
38	  status?: string;
39	  includeResolved?: true;
40	  sort?: string;
41	  q?: string;
42	}
43	
44	async function request<T>(
45	  path: string,
46	  options: RequestInit = {},
47	  session?: Session,
48	): Promise<T> {
49	  const headers: Record<string, string> = {
50	    ...(options.headers as Record<string, string>),
51	  };
52	
53	  if (options.method && ["POST", "PUT", "PATCH"].includes(options.method)) {
54	    headers["Content-Type"] = "application/json";
55	  }
56	
57	  if (session?.agentId) {
58	    headers["X-Bayes-Agent-Id"] = session.agentId;
59	  }
60	
61	  const res = await fetch(`${API_BASE}${path}`, {
62	    ...options,
63	    headers,
64	  });
65	
66	  const body = await res.json();
67	
68	  if (!res.ok) {
69	    const err = body as ApiError;
70	    throw new BayesApiError(
71	      res.status,
72	      err.error?.code ?? "unknown_error",
73	      err.error?.details ?? {},
74	    );
75	  }
76	
77	  return body as T;
78	}
79	
80	export function normalizeMarketListFilters(
81	  filters?: MarketListFilterInput,
82	): NormalizedMarketListFilters {
83	  const status = typeof filters === "string"
84	    ? filters
85	    : filters?.status;
86	  const includeResolved = (
87	    typeof filters !== "string"
88	    && filters?.includeResolved === true
89	  ) || status === "resolved";
90	  const sort = typeof filters !== "string" ? filters?.sort : undefined;
91	  const q = typeof filters !== "string" ? filters?.q?.trim() || undefined : undefined;
92	
93	  return {
94	    ...(status ? { status } : {}),
95	    ...(includeResolved ? { includeResolved: true } : {}),
96	    ...(sort ? { sort } : {}),
97	    ...(q ? { q } : {}),
